contracts/DJZSAgentRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

contract DJZSAgentRegistry is Ownable {
    struct AgentInfo {
        string name;
        string metadataUri;
        address owner;
        bool active;
        uint256 registeredAt;
    }

    mapping(address => AgentInfo) public agents;
    mapping(address => bool) public isRegistered;
    address[] public agentList;

    event AgentRegistered(address indexed agent, string name, address indexed agentOwner);
    event AgentDeactivated(address indexed agent);
    event AgentReactivated(address indexed agent);
    event AgentMetadataUpdated(address indexed agent, string metadataUri);

    constructor() Ownable(msg.sender) {}

    function registerAgent(
        address agent,
        string calldata name,
        string calldata metadataUri
    ) external {
        require(agent != address(0), "DJZSAgentRegistry: zero address");
        require(!isRegistered[agent], "DJZSAgentRegistry: already registered");
        require(
            msg.sender == agent || msg.sender == owner(),
            "DJZSAgentRegistry: unauthorized"
        );

        agents[agent] = AgentInfo({
            name: name,
            metadataUri: metadataUri,
            owner: msg.sender,
            active: true,
            registeredAt: block.timestamp
        });
        isRegistered[agent] = true;
        agentList.push(agent);

        emit AgentRegistered(agent, name, msg.sender);
    }

    function deactivateAgent(address agent) external {
        require(isRegistered[agent], "DJZSAgentRegistry: not registered");
        require(
            msg.sender == agents[agent].owner || msg.sender == owner(),
            "DJZSAgentRegistry: unauthorized"
        );

        agents[agent].active = false;
        emit AgentDeactivated(agent);
    }

    function reactivateAgent(address agent) external {
        require(isRegistered[agent], "DJZSAgentRegistry: not registered");
        require(
            msg.sender == agents[agent].owner || msg.sender == owner(),
            "DJZSAgentRegistry: unauthorized"
        );

        agents[agent].active = true;
        emit AgentReactivated(agent);
    }

    function updateMetadata(address agent, string calldata metadataUri) external {
        require(isRegistered[agent], "DJZSAgentRegistry: not registered");
        require(
            msg.sender == agents[agent].owner || msg.sender == owner(),
            "DJZSAgentRegistry: unauthorized"
        );

        agents[agent].metadataUri = metadataUri;
        emit AgentMetadataUpdated(agent, metadataUri);
    }

    function getAgent(address agent) external view returns (
        string memory name,
        string memory metadataUri,
        address agentOwner,
        bool active,
        uint256 registeredAt
    ) {
        AgentInfo storage info = agents[agent];
        return (info.name, info.metadataUri, info.owner, info.active, info.registeredAt);
    }

    function getAgentCount() external view returns (uint256) {
        return agentList.length;
    }

    function getAgentAtIndex(uint256 index) external view returns (address) {
        require(index < agentList.length, "DJZSAgentRegistry: index out of bounds");
        return agentList[index];
    }
}

contracts/DJZSEscrowLock.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

contract DJZSEscrowLock is Ownable {
    using SafeERC20 for IERC20;

    enum EscrowStatus { Pending, Settled, Refunded }

    struct Escrow {
        address creator;
        address recipient;
        uint256 amount;
        bytes32 executionTraceHash;
        bool settled;
        EscrowStatus status;
        string irisTxId;
    }

    IERC20 public immutable paymentToken;
    address public settlementAgent;
    uint256 public nextEscrowId;

    mapping(uint256 => Escrow) public escrows;

    event EscrowCreated(
        uint256 indexed escrowId,
        address creator,
        address recipient,
        uint256 amount,
        bytes32 executionTraceHash
    );

    event AuditPending(
        uint256 indexed escrowId,
        address creator,
        address recipient,
        bytes32 executionTraceHash,
        uint256 amount
    );

    event EscrowSettled(
        uint256 indexed escrowId,
        bool passed,
        string irisTxId
    );

    event EscrowRefunded(uint256 indexed escrowId);

    modifier onlySettlementAgent() {
        require(
            msg.sender == settlementAgent || msg.sender == owner(),
            "DJZSEscrowLock: caller is not the settlement agent"
        );
        _;
    }

    constructor(address _paymentToken) Ownable(msg.sender) {
        paymentToken = IERC20(_paymentToken);
        settlementAgent = msg.sender;
    }

    function setSettlementAgent(address _agent) external onlyOwner {
        settlementAgent = _agent;
    }

    function createEscrow(
        address recipient,
        uint256 amount,
        bytes32 executionTraceHash
    ) external returns (uint256 escrowId) {
        require(recipient != address(0), "DJZSEscrowLock: zero recipient");
        require(amount > 0, "DJZSEscrowLock: zero amount");

        paymentToken.safeTransferFrom(msg.sender, address(this), amount);

        escrowId = nextEscrowId++;
        escrows[escrowId] = Escrow({
            creator: msg.sender,
            recipient: recipient,
            amount: amount,
            executionTraceHash: executionTraceHash,
            settled: false,
            status: EscrowStatus.Pending,
            irisTxId: ""
        });

        emit EscrowCreated(escrowId, msg.sender, recipient, amount, executionTraceHash);
        emit AuditPending(escrowId, msg.sender, recipient, executionTraceHash, amount);
    }

    function settleEscrow(
        uint256 escrowId,
        bool passed,
        string calldata irisTxId
    ) external onlySettlementAgent {
        Escrow storage escrow = escrows[escrowId];
        require(escrow.creator != address(0), "DJZSEscrowLock: escrow does not exist");
        require(!escrow.settled, "DJZSEscrowLock: already settled");

        escrow.settled = true;
        escrow.status = EscrowStatus.Settled;
        escrow.irisTxId = irisTxId;

        if (passed) {
            paymentToken.safeTransfer(escrow.recipient, escrow.amount);
        } else {
            paymentToken.safeTransfer(escrow.creator, escrow.amount);
        }

        emit EscrowSettled(escrowId, passed, irisTxId);
    }

    function refundEscrow(uint256 escrowId) external onlyOwner {
        Escrow storage escrow = escrows[escrowId];
        require(escrow.creator != address(0), "DJZSEscrowLock: escrow does not exist");
        require(!escrow.settled, "DJZSEscrowLock: already settled");

        escrow.settled = true;
        escrow.status = EscrowStatus.Refunded;
        paymentToken.safeTransfer(escrow.creator, escrow.amount);

        emit EscrowRefunded(escrowId);
    }

    function getEscrow(uint256 escrowId) external view returns (
        address creator,
        address recipient,
        uint256 amount,
        bytes32 executionTraceHash,
        bool settled
    ) {
        Escrow storage escrow = escrows[escrowId];
        return (
            escrow.creator,
            escrow.recipient,
            escrow.amount,
            escrow.executionTraceHash,
            escrow.settled
        );
    }
}

contracts/DJZSLogicTrustScore.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

contract DJZSLogicTrustScore is Ownable {
    struct TrustRecord {
        uint256 riskScore;
        string verdict;
        string[] flags;
        uint256 timestamp;
        string irysTxId;
    }

    mapping(address => TrustRecord[]) public agentHistory;
    mapping(address => uint256) public latestRiskScore;
    mapping(address => string) public latestVerdict;
    mapping(address => uint256) public auditCount;

    mapping(address => bool) public authorizedWriters;

    event ScoreUpdated(
        address indexed agent,
        uint256 riskScore,
        string verdict,
        string[] flags,
        string irysTxId,
        uint256 timestamp
    );

    event WriterAuthorized(address indexed writer);
    event WriterRevoked(address indexed writer);

    modifier onlyWriter() {
        require(
            authorizedWriters[msg.sender] || msg.sender == owner(),
            "DJZSLogicTrustScore: caller is not an authorized writer"
        );
        _;
    }

    constructor() Ownable(msg.sender) {
        authorizedWriters[msg.sender] = true;
    }

    function authorizeWriter(address writer) external onlyOwner {
        authorizedWriters[writer] = true;
        emit WriterAuthorized(writer);
    }

    function revokeWriter(address writer) external onlyOwner {
        authorizedWriters[writer] = false;
        emit WriterRevoked(writer);
    }

    function updateScore(
        address agent,
        uint256 riskScore,
        string calldata verdict,
        string[] calldata flags,
        string calldata irysTxId
    ) external onlyWriter {
        require(riskScore <= 100, "DJZSLogicTrustScore: risk score must be 0-100");
        require(agent != address(0), "DJZSLogicTrustScore: zero address");

        TrustRecord memory record = TrustRecord({
            riskScore: riskScore,
            verdict: verdict,
            flags: flags,
            timestamp: block.timestamp,
            irysTxId: irysTxId
        });

        agentHistory[agent].push(record);
        latestRiskScore[agent] = riskScore;
        latestVerdict[agent] = verdict;
        auditCount[agent] += 1;

        emit ScoreUpdated(agent, riskScore, verdict, flags, irysTxId, block.timestamp);
    }

    function getLatestScore(address agent) external view returns (
        uint256 riskScore,
        string memory verdict,
        uint256 timestamp,
        uint256 totalAudits
    ) {
        uint256 count = auditCount[agent];
        if (count == 0) {
            return (0, "", 0, 0);
        }
        TrustRecord storage record = agentHistory[agent][count - 1];
        return (record.riskScore, record.verdict, record.timestamp, count);
    }

    function getAuditRecord(address agent, uint256 index) external view returns (
        uint256 riskScore,
        string memory verdict,
        string[] memory flags,
        uint256 timestamp,
        string memory irysTxId
    ) {
        require(index < auditCount[agent], "DJZSLogicTrustScore: index out of bounds");
        TrustRecord storage record = agentHistory[agent][index];
        return (record.riskScore, record.verdict, record.flags, record.timestamp, record.irysTxId);
    }

    function getAuditHistory(address agent) external view returns (uint256 count) {
        return auditCount[agent];
    }
}

contracts/DJZSStaking.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

contract DJZSStaking is Ownable {
    using SafeERC20 for IERC20;

    struct StakeInfo {
        uint256 amount;
        uint256 stakedAt;
        uint256 lockUntil;
        bool active;
    }

    IERC20 public immutable stakingToken;
    uint256 public minimumStake;
    uint256 public lockDuration;
    uint256 public totalStaked;

    mapping(address => StakeInfo) public stakes;
    mapping(address => bool) public isStaker;

    event Staked(address indexed staker, uint256 amount, uint256 lockUntil);
    event Unstaked(address indexed staker, uint256 amount);
    event Slashed(address indexed staker, uint256 amount, string reason);
    event MinimumStakeUpdated(uint256 newMinimum);
    event LockDurationUpdated(uint256 newDuration);

    constructor(
        address _stakingToken,
        uint256 _minimumStake,
        uint256 _lockDuration
    ) Ownable(msg.sender) {
        stakingToken = IERC20(_stakingToken);
        minimumStake = _minimumStake;
        lockDuration = _lockDuration;
    }

    function stake(uint256 amount) external {
        require(amount >= minimumStake, "DJZSStaking: below minimum stake");
        require(!stakes[msg.sender].active, "DJZSStaking: already staked");

        stakingToken.safeTransferFrom(msg.sender, address(this), amount);

        uint256 lockUntil = block.timestamp + lockDuration;
        stakes[msg.sender] = StakeInfo({
            amount: amount,
            stakedAt: block.timestamp,
            lockUntil: lockUntil,
            active: true
        });
        isStaker[msg.sender] = true;
        totalStaked += amount;

        emit Staked(msg.sender, amount, lockUntil);
    }

    function unstake() external {
        StakeInfo storage info = stakes[msg.sender];
        require(info.active, "DJZSStaking: no active stake");
        require(block.timestamp >= info.lockUntil, "DJZSStaking: still locked");

        uint256 amount = info.amount;
        info.active = false;
        isStaker[msg.sender] = false;
        totalStaked -= amount;

        stakingToken.safeTransfer(msg.sender, amount);

        emit Unstaked(msg.sender, amount);
    }

    function slash(address staker, uint256 amount, string calldata reason) external onlyOwner {
        StakeInfo storage info = stakes[staker];
        require(info.active, "DJZSStaking: no active stake");
        require(amount <= info.amount, "DJZSStaking: slash exceeds stake");

        info.amount -= amount;
        totalStaked -= amount;

        if (info.amount == 0) {
            info.active = false;
            isStaker[staker] = false;
        }

        stakingToken.safeTransfer(owner(), amount);

        emit Slashed(staker, amount, reason);
    }

    function setMinimumStake(uint256 _minimumStake) external onlyOwner {
        minimumStake = _minimumStake;
        emit MinimumStakeUpdated(_minimumStake);
    }

    function setLockDuration(uint256 _lockDuration) external onlyOwner {
        lockDuration = _lockDuration;
        emit LockDurationUpdated(_lockDuration);
    }

    function getStake(address staker) external view returns (
        uint256 amount,
        uint256 stakedAt,
        uint256 lockUntil,
        bool active
    ) {
        StakeInfo storage info = stakes[staker];
        return (info.amount, info.stakedAt, info.lockUntil, info.active);
    }
}

